import{j as e}from"./index-BeW3Ogyy.js";function r(){return e.jsxs(e.Fragment,{children:[e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:4",children:"Every Amazon DSP owner has the same Monday morning ritual: open Cortex, look at the weekly scorecard, and try to work out which driver, which route, or which day dragged the numbers. If your status moved from Fantastic Plus to Fantastic — or worse, from Fantastic to Great — you've got a week to figure out what broke and prove you can fix it."}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:10",children:"The good news: scorecards almost always slip for predictable, fixable reasons. Below is the per-metric playbook we see working with UK Amazon DSPs."}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:15",children:"What the Amazon Cortex scorecard actually measures"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:16",children:"The Cortex DA scorecard rolls six core metrics into a weekly status banner (Fantastic Plus, Fantastic, Great, Fair, Poor). Each metric is a leading indicator of how well your fleet executed against Amazon's promise to the customer. Understanding them in plain English is the first step:"}),e.jsxs("ul",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:21",children:[e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:22",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:23",children:"DCR (Delivery Completion Rate)"})," — the share of assigned stops that were actually completed. Misses come from undelivered packages, returns to station, and incomplete waves."]}),e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:26",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:27",children:"DPMO (Defects Per Million Opportunities)"})," — physical defects: damages, missing items, wrong addresses, lost packages. Counted per million stops, so even small absolute numbers move the metric."]}),e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:31",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:32",children:"DNR (Delivered Not Received)"})," — customer-reported claims that a package was marked delivered but never arrived. Often tied to specific drivers or specific addresses."]}),e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:35",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:36",children:"POD (Photo on Delivery)"})," — compliance with the photo-on-delivery requirement for drop-offs. Low POD scores almost always cluster around a small number of drivers."]}),e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:39",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:40",children:"CC (Contact Compliance)"})," — drivers using the Mentor app to contact customers when deliveries can't complete. Skipped contacts compound into DNR and DCR misses downstream."]}),e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:43",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:44",children:"CDF (Customer Delivery Feedback)"})," — direct customer feedback rolled up into a score. Soft signal but it correlates tightly with CC and POD."]})]}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:49",children:"Why scorecards drift, even when nothing has obviously gone wrong"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:50",children:`Most DSPs we talk to don't have a "bad fleet" problem. They have a visibility problem. You see the weekly scorecard on Monday — but the events that produced it happened across hundreds of stops, on ten different routes, over seven days. By the time you're trying to fix it, the people involved have forgotten the specifics.`}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:56",children:"The structural fix is to look at metrics live, per driver, mid-week — not as a summary after the fact. The tactical fixes below assume you can."}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:61",children:"DCR — lift it with route-handoff discipline"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:62",children:"DCR drops happen on the routes that finish late, run out of time, or get returned partially complete. Two interventions:"}),e.jsxs("ul",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:66",children:[e.jsx("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:67",children:"Track planned vs actual finish times per route. Routes that consistently finish in the red are either over-stopped or assigned to drivers who need a route swap."}),e.jsx("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:71",children:'Cut "return to station with packages" events. When a driver is on track to RTS with parcels, get them on the phone before the end of the wave — almost always you can either reroute the remaining stops or get them a one-hour extension.'})]}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:78",children:"DPMO — fix the upstream van check, not the downstream defect"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:79",children:"Most DPMO defects you can prevent — damaged parcels, wrong-address attempts, missing items — trace back to two events: a sloppy van load and an unchecked van. Both are upstream of dispatch."}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:83",children:"A daily van inspection with photos (yes, every day) catches the small issues that turn into customer complaints by Friday. And a pre-departure check on package counts catches the missing-item DPMO hits before the van leaves the station. The drivers who skip these checks are usually the drivers driving your DPMO."}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:90",children:"DNR — investigate every claim, even when it feels unfair"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:91",children:"DNRs feel like the metric you can't control, but the patterns are obvious once you look. Claims tend to cluster around three things: specific drivers, specific addresses, and specific times of day (usually evening drops in low-light conditions). Pull the last 30 days of DNR claims, sort by driver, and the top two names will almost always be over-represented. That's where the conversation starts."}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:98",children:"POD — make it visible to drivers daily, not weekly"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:99",children:"POD compliance is the easiest metric to fix because it's a behaviour, not a skill. The drivers with low POD scores almost always know exactly which photos they skipped — they just don't see the consequence until your Monday meeting. Surface every driver's personal POD score back to them daily, on their phone, and the metric moves within two weeks."}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:106",children:"CC — train it as a habit, not a one-off briefing"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:107",children:"Contact Compliance is about drivers actually using the Mentor app's contact buttons when they can't complete a delivery. The fix is repetition: review CC misses in the morning huddle, the same way you review safety. After three weeks of consistent feedback, drivers internalise it."}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:113",children:"CDF — the lagging indicator that confirms the rest is working"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:114",children:"Customer Delivery Feedback rises automatically when POD and CC rise. There's no separate lever for it. If the other five metrics are improving and CDF isn't, look at handover quality — are drivers leaving packages in places customers don't expect, or rushing the doorstep interaction."}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:120",children:"The Monday-to-Friday review rhythm"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:121",children:"Owners who consistently hit Fantastic Plus run the same loop:"}),e.jsxs("ul",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:124",children:[e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:125",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:126",children:"Monday:"})," review the previous week's scorecard with the OSM and identify the one or two metrics most at risk."]}),e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:129",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:130",children:"Tuesday–Thursday:"})," short morning huddles focused on yesterday's actual driver-level numbers, not the fleet average."]}),e.jsxs("li",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:133",children:[e.jsx("strong",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:134",children:"Friday:"})," a quick scan of the week's trajectory — escalations for any driver consistently below standard, recognition for the top performers."]})]}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:138",children:"The thing that breaks this loop, every time, is data. If your OSM is rebuilding metric tables in Excel every morning instead of running the huddle, the loop dies by Wednesday."}),e.jsx("h2",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:143",children:"Where DSPOps fits in"}),e.jsx("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:144",children:"DSPOps connects to Amazon Cortex and pulls every scorecard metric in live, per driver and per route. Your OSM opens the dashboard, sees the three drivers most likely to drag this week's score, and runs the huddle in two minutes. Drivers see their own metrics inside the driver portal — the ones who care about being top of the leaderboard self-correct without a meeting."}),e.jsxs("p",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:150",children:["If you want to see what your DSP's scorecard looks like inside DSPOps, you can"," ",e.jsx("a",{"data-loc":"client\\src\\content\\blog\\improve-amazon-cortex-scorecard.tsx:152",href:"#book-demo",className:"text-brand font-semibold hover:underline",children:"book a 20-minute demo"})," ","— we'll set up your data live during the call."]})]})}const a=[{slug:"improve-amazon-cortex-scorecard",title:"How to improve your Amazon Cortex scorecard",description:"A practical guide for DSP owners on lifting DCR, DPMO, DNRs, POD, CC, and CDF — week by week.",excerpt:"Every Amazon DSP owner stares at the Cortex scorecard on Monday. Here's the per-metric playbook to actually move the numbers.",date:"2026-05-18",readingMinutes:7,Body:r}];function s(t){return a.find(o=>o.slug===t)}export{a as b,s as g};
